  val allowedSchemes = Set("https")

  def isPrivateOrLocalAddress(address: InetAddress): Boolean = {
    address.isLoopbackAddress ||
      address.isLinkLocalAddress ||
      address.isSiteLocalAddress ||
      address.isAnyLocalAddress ||
      address.getHostAddress == "0.0.0.0" ||
      address.getHostAddress.startsWith("169.254.") ||
      address.getHostAddress.startsWith("127.") ||
      address.getHostAddress.startsWith("10.") ||
      address.getHostAddress.startsWith("172.16.") ||
