      address.getHostAddress.startsWith("172.30.") ||
      address.getHostAddress.startsWith("172.31.") ||
      address.getHostAddress.startsWith("192.168.") ||
      address.getHostAddress.startsWith("fc00:") ||
      address.getHostAddress.startsWith("fd00:") ||
      address.getHostAddress.startsWith("fe80:")
  }

  def validateUrl(url: String): Either[String, URI] = {
    Try(new URI(url)) match {
      case Failure(_) => Left("Invalid URL format")
      case Success(uri) =>
        val scheme = Option(uri.getScheme).map(_.toLowerCase)
        val host = Option(uri.getHost)

        if (scheme.isEmpty || !allowedSchemes.contains(scheme.get)) {
          Left(s"Scheme must be one of: ${allowedSchemes.mkString(", ")}")
        } else if (host.isEmpty) {
          Left("URL must contain a valid host")
        } else if (!allowedHosts.contains(host.get.toLowerCase)) {
          Left(s"Host not in allowlist. Allowed hosts: ${allowedHosts.mkString(", ")}")
        } else {
          Try(InetAddress.getAllByName(host.get)) match {
            case Failure(_) => Left("Unable to resolve hostname")
            case Success(addresses) =>
              if (addresses.exists(isPrivateOrLocalAddress)) {
                Left("URL resolves to private or internal IP address")
              } else {
                Right(uri)
              }
          }
        }
    }
  }

  def fetchContent(url: String): Future[Either[String, String]] = {
    validateUrl(url) match {
      case Left(error) => Future.successful(Left(error))
      case Right(validUri) =>
        val request = HttpRequest(
          method = HttpMethods.GET,
          uri = validUri.toString,
          headers = List(
            headers.`User-Agent`("WebhookProxy/1.0")
