        Http()
          .singleRequest(
            request,
            settings = ConnectionPoolSettings(system)
              .withMaxRedirects(0)
          )
          .flatMap { response =>
            response.status match {
              case StatusCodes.OK =>
                Unmarshal(response.entity).to[String].map(Right(_))
